// category → subcategory (demo)
const CATEGORY_MAP = {
  Fiction: ['Fantasy', 'Science Fiction', 'Mystery', 'Romance', 'Thriller', 'Historical'],
  'Non-Fiction': ['Memoir', 'Self-Help', 'Business', 'Health', 'History', 'Technology'],
  Children: ['Picture Book', 'Chapter Book', 'Young Adult'],
  Education: ['Textbook', 'Workbook', 'Reference'],
};

const FILE_TYPES = [
  'Main Manuscript',
  'Book Cover',
  'Chapter',
  'Appendix',
  'Bibliography',
  'Index',
  'Preface',
  'Introduction',
  'Acknowledgments',
  'Other',
];

const canReadAsText = (file) => {
  if (!file) return false;
  const name = (file.name || '').toLowerCase();
  if (file.type && file.type.startsWith('text/')) return true;
  return name.endsWith('.txt') || name.endsWith('.md') || name.endsWith('.markdown');
};

export default function UploadStep() {
  const fileRef = useRef();
  const {
    uploadPhase, setUploadPhase,
    manuscriptFiles, addFile, updateFile, removeFile,
    bookDetails, setBookDetails,
    primaryFileId, setPrimaryFileId,
  } = useWorkflow();

  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);

  const handleFiles = async (files) => {
    if (!files || files.length === 0) return;
    const file = files[0];
    const id = uuidv4();

    const objectUrl = URL.createObjectURL(file);
    let textContent = '';
    if (canReadAsText(file)) {
      try { textContent = await file.text(); } catch { /* noop */ }
    }
// ACTION: need to fix this so it could be any file type 
    addFile({
      id,
      name: file.name,
      size: file.size,
      mimeType: file.type,
      status: 'uploading',
      progress: 0,
      fileType: 'Main Manuscript',
      blob: file,
      objectUrl,
      textContent,
    });

    if (!primaryFileId) setPrimaryFileId(id);

    setIsUploading(true);
    try {
      const resp = await uploadFile(file, (pct) => {
        setProgress(pct);
        updateFile(id, { progress: pct });
      });
      updateFile(id, { status: 'done', progress: 100, serverResponse: resp?.data });
      setUploadPhase('ready');
    } catch (err) {
      console.error('Upload failed', err);
      updateFile(id, { status: 'done', progress: 100, serverResponse: null, error: 'Local only' });
      setUploadPhase('ready');
    } finally {
      setIsUploading(false);
    }
  };

  const onChoose = (e) => handleFiles(e.target.files);
  const onDrop = (e) => { e.preventDefault(); handleFiles(e.dataTransfer.files); };
// ACTION: fix this so it could be any file type outside of Main Manuscript 
  const onChangeFileType = (id, type) => {
    updateFile(id, { fileType: type });
    if (type === 'Main Manuscript') setPrimaryFileId(id);
  };

  const categories = useMemo(() => Object.keys(CATEGORY_MAP), []);
  const subcategories = useMemo(
    () => (bookDetails.category ? CATEGORY_MAP[bookDetails.category] || [] : []),
    [bookDetails.category]
  );

  const canStartAnalysis = manuscriptFiles.some((f) => f.status === 'done');
  const canContinueMetadata =
    (bookDetails.title?.trim()?.length ?? 0) > 0 &&
    (bookDetails.category?.length ?? 0) > 0;

  return (
    <div>
      {/* Phase 1: select / drop area */}
      {uploadPhase === 'select' && (
        <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 flex flex-col items-center">
          <div className="mb-4 text-slate-700 text-center">
            <h3 className="text-2xl font-semibold">Upload Your Manuscript</h3>
            <p className="text-sm text-slate-500">PDF, DOCX, TXT, MD — up to 50MB</p>
          </div>

          <div
            onDrop={onDrop}
            onDragOver={(e) => e.preventDefault()}
            className="w-full py-12 flex items-center justify-center rounded-lg bg-gradient-to-br from-slate-50 to-white"
          >
            <div className="text-center">
              <input ref={fileRef} type="file" onChange={onChoose} className="hidden" />
              <button
                onClick={() => fileRef.current.click()}
                className="px-6 py-3 bg-blue-600 text-white rounded-md shadow hover:bg-blue-700"
              >
                Upload a file
              </button>
              <div className="mt-4 text-sm text-slate-500">or drag and drop here</div>
            </div>
          </div>

          <div className="mt-6 w-full">
            {isUploading && (
              <div className="w-full bg-slate-100 rounded overflow-hidden">
                <div style={{ width: `${progress}%` }} className="h-2 bg-blue-600 transition-all" />
                <div className="text-sm text-slate-600 mt-2">Uploading: {progress}%</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Phase 2: Ready for Analysis card + actions */}
      {uploadPhase === 'ready' && (
        <div className="space-y-6">
          <div className="flex items-center gap-2 text-emerald-600 font-medium">
            <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-emerald-100">✓</span>
            Ready for Analysis
          </div>

          <div className="space-y-3">
            {manuscriptFiles.map((f) => (
              <div
                key={f.id}
                className="border rounded-xl bg-white shadow-sm px-4 py-3 flex items-center justify-between"
              >
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-md bg-slate-100 flex items-center justify-center">📄</div>
                  <div>
                    <div className="font-medium text-slate-900">{f.name}</div>
                    <div className="text-xs text-slate-500">{(f.size / 1024).toFixed(2)} KB</div>
                    {primaryFileId === f.id && (
                      <div className="text-xs text-blue-600 mt-1">Primary manuscript</div>
                    )}
                  </div>
                </div>
{/* ACTION: fix this so it doesnt reference just Main Manuscirpt*/}
                <div className="flex items-center gap-2">
                  <select
                    value={f.fileType || 'Main Manuscript'}
                    onChange={(e) => onChangeFileType(f.id, e.target.value)}
                    className="text-sm border rounded-md px-2 py-1"
                  >
                    {FILE_TYPES.map((t) => (
                      <option key={t} value={t}>{t}</option>
                    ))}
                  </select>
                  <button
                    onClick={() => removeFile(f.id)}
                    className="text-slate-400 hover:text-red-500"
                    title="Remove"
                  >
                    ✕
                  </button>
                </div>
              </div>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <button
              type="button"
              onClick={() => fileRef.current?.click()}
              className="inline-flex items-center gap-2 px-4 py-2 rounded-md border border-slate-300 bg-white"
            >
              <span>＋</span> Add Another File
            </button>
            <button
              type="button"
              disabled={!canStartAnalysis}
              onClick={() => setUploadPhase('metadata')}
              className={`inline-flex items-center gap-2 px-5 py-2 rounded-md text-white ${
                canStartAnalysis ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300'
              }`}
            >
              Start AI Analysis →
            </button>
          </div>
        </div>
      )}

      {/* Phase 3: Metadata form */}
      {uploadPhase === 'metadata' && (
        <div className="space-y-8">
          <div className="border rounded-2xl p-6 bg-white">
            <h3 className="text-2xl font-semibold mb-4">Basic Information</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <label className="block text-sm text-slate-600 mb-1">Book Title *</label>
                <input
                  type="text"
                  value={bookDetails.title || ''}
                  onChange={(e) => setBookDetails((b) => ({ ...b, title: e.target.value }))}
                  placeholder="Enter your book title"
                  className="w-full border rounded-md px-3 py-2"
                />
              </div>

              <div>
                <label className="block text-sm text-slate-600 mb-1">Category *</label>
                <select
                  value={bookDetails.category || ''}
                  onChange={(e) =>
                    setBookDetails((b) => ({
                      ...b,
                      category: e.target.value,
                      subcategory: '',
                    }))
                  }
                  className="w-full border rounded-md px-3 py-2"
                >
                  <option value="" disabled>Select category</option>
                  {categories.map((c) => (
                    <option key={c} value={c}>{c}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm text-slate-600 mb-1">Subcategory</label>
                <select
                  value={bookDetails.subcategory || ''}
                  onChange={(e) => setBookDetails((b) => ({ ...b, subcategory: e.target.value }))}
                  disabled={!subcategories.length}
                  className="w-full border rounded-md px-3 py-2 disabled:bg-slate-50"
                >
                  <option value="" disabled>
                    {subcategories.length ? 'Select subcategory' : 'Select a category first'}
                  </option>
                  {subcategories.map((s) => (
                    <option key={s} value={s}>{s}</option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          <div className="border rounded-2xl p-6 bg-white">
            <h3 className="text-2xl font-semibold mb-4">Organize Your Files</h3>
            <p className="text-sm text-slate-500 mb-4">
              Tag your files to help organize them properly. Files tagged as “Book Cover” will remain separate.
            </p>

            <div className="space-y-3">
              {manuscriptFiles.map((f) => (
                <div
                  key={f.id}
                  className="border rounded-xl bg-white px-4 py-3 flex items-center justify-between"
                >
                  <div className="flex items-center gap-3">
                    <span className="cursor-grab">⋮⋮</span>
                    <div className="w-8 h-8 rounded-md bg-slate-100 flex items-center justify-center">📄</div>
                    <div>
                      <div className="font-medium">{f.name}</div>
                      <div className="text-xs text-slate-500">{(f.size / 1024).toFixed(2)} KB</div>
                    </div>
                  </div>
{/*Change so not reference just filemtype Manuscrit Main */}
                  <div className="flex items-center gap-2">
                    <select
                      value={f.fileType || 'Main Manuscript'}
                      onChange={(e) => onChangeFileType(f.id, e.target.value)}
                      className="text-sm border rounded-md px-2 py-1"
                    >
                      {FILE_TYPES.map((t) => (
                        <option key={t} value={t}>{t}</option>
                      ))}
                    </select>
                    <button
                      onClick={() => removeFile(f.id)}
                      className="text-slate-400 hover:text-red-500"
                      title="Remove"
                    >
                      🗑
                    </button>
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-4">
              <button
                type="button"
                onClick={() => fileRef.current?.click()}
                className="inline-flex items-center gap-2 px-4 py-2 rounded-md border border-slate-300 bg-white"
              >
                ＋ Add Another File
              </button>
              <input ref={fileRef} type="file" onChange={onChoose} className="hidden" />
            </div>
          </div>

          <div className="flex justify-end">
            {!canContinueMetadata && (
              <div className="text-sm text-slate-500 mr-3">
                Add a title and category to continue.
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
